"use client";
import { useState, useEffect } from "react";
import { ChevronDown, Wallet as WalletIcon, Tag } from "lucide-react";

export default function ExpensePage() {
    const [wallets, setWallets] = useState<any[]>([]);
    const [selectedWallet, setSelectedWallet] = useState<any>(null);
    const [amount, setAmount] = useState("");
    const [category, setCategory] = useState("Makan & Minum");
    const [description, setDescription] = useState("");
    const [loading, setLoading] = useState(false);
    const [isWalletOpen, setIsWalletOpen] = useState(false);

    useEffect(() => {
        fetch("/api/dashboard/summary").then(res => res.json()).then(data => {
            const list = data.walletDetails || [];
            setWallets(list);
            if (list.length > 0) setSelectedWallet(list[0]);
        });
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedWallet) return alert("Pilih akun terlebih dahulu!");

        setLoading(true);
        const res = await fetch("/api/transactions/expense", {
            method: "POST",
            body: JSON.stringify({ 
                amount, 
                description, 
                walletId: Number(selectedWallet.id), 
                categoryName: category 
            }),
        });

        if (res.ok) {
            alert("Pengeluaran berhasil dicatat!");
            window.location.href = "/dashboard";
        }
        setLoading(false);
    };

    return (
        <div className="max-w-2xl mx-auto py-8">
            <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
                <header className="mb-8">
                    <h2 className="text-2xl font-bold text-slate-800">Catat Pengeluaran 💸</h2>
                    <p className="text-slate-500 text-sm mt-1">Uang yang keluar hari ini buat apa saja?</p>
                </header>

                <form onSubmit={handleSubmit} className="space-y-6">
                    {/* NOMINAL */}
                    <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 text-center">
                        <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Nominal (Rp)</label>
                        <input 
                            type="number" required placeholder="0"
                            className="w-full bg-transparent border-none text-4xl font-bold text-red-600 focus:ring-0 p-0 mt-2 text-center"
                            onChange={(e) => setAmount(e.target.value)}
                        />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {/* CUSTOM DROPDOWN SUMBER DANA */}
                        <div className="relative">
                            <label className="text-sm font-semibold text-slate-600 block mb-2">Sumber Dana</label>
                            <div 
                                onClick={() => setIsWalletOpen(!isWalletOpen)}
                                className="w-full p-4 pl-12 bg-slate-50 rounded-xl border border-transparent hover:border-red-200 transition-all cursor-pointer flex items-center justify-between"
                            >
                                <div className="absolute left-4 text-slate-400">
                                    <WalletIcon size={18} />
                                </div>
                                <span className="font-medium text-slate-700">
                                    {selectedWallet ? selectedWallet.name : "Pilih Akun..."}
                                </span>
                                <ChevronDown className={`text-slate-400 transition-transform ${isWalletOpen ? 'rotate-180' : ''}`} size={18} />
                            </div>

                            {isWalletOpen && (
                                <div className="absolute z-50 w-full mt-2 bg-white border border-slate-100 rounded-xl shadow-xl max-h-48 overflow-y-auto">
                                    {wallets.map((w) => (
                                        <div 
                                            key={w.id}
                                            onClick={() => { setSelectedWallet(w); setIsWalletOpen(false); }}
                                            className="p-4 hover:bg-red-50 cursor-pointer flex justify-between items-center border-b border-slate-50 last:border-none"
                                        >
                                            <span className="font-medium text-slate-700">{w.name}</span>
                                            <span className="text-xs text-red-400 font-bold">Rp {w.balance.toLocaleString("id-ID")}</span>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* KATEGORI */}
                        <div className="relative">
                            <label className="text-sm font-semibold text-slate-600 block mb-2">Kategori</label>
                            <select 
                                className="w-full p-4 pl-12 bg-slate-50 rounded-xl appearance-none border-none focus:ring-2 focus:ring-blue-500 font-medium text-slate-700"
                                onChange={(e) => setCategory(e.target.value)}
                            >
                                {["Makan & Minum", "Transportasi", "Kuliah/Informatika", "Hiburan", "Lain-lain"].map(cat => (
                                    <option key={cat} value={cat}>{cat}</option>
                                ))}
                            </select>
                            <Tag className="absolute left-4 top-[70%] -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                            <ChevronDown className="absolute right-4 top-[70%] -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                    </div>

                    {/* KETERANGAN */}
                    <div>
                        <label className="text-sm font-semibold text-slate-600 block mb-2">Keterangan Tambahan</label>
                        <textarea 
                            placeholder="Contoh: Beli kopi di kantin Unpad"
                            className="w-full p-4 bg-slate-50 rounded-xl border-none focus:ring-2 focus:ring-blue-500"
                            rows={3}
                            onChange={(e) => setDescription(e.target.value)}
                        />
                    </div>

                    <button
                        disabled={loading}
                        className="w-full bg-slate-900 text-white p-5 rounded-2xl font-bold text-lg hover:bg-red-600 transition-all active:scale-[0.98] disabled:opacity-50"
                    >
                        {loading ? "Menyimpan..." : "Simpan Pengeluaran"}
                    </button>
                </form>
            </div>
        </div>
    );
}